Javascript.validate:
var err = null;
var isFuture = isFutureDate(Services.getValue(DateOfApplication.dataBinding));
if( null != isFuture && isFuture )
{  err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInTheFuture_Msg");
}			
else if( isNonWorkingDate(isFuture))
{	err = ErrorCode.getErrorCode("CaseMan_dateNonWorkingDay_Msg");
}			

return err;

